  1→.layout {
  2→  display: grid;
  3→  grid-template-rows: var(--toolbar-height, 52px) 1fr;
  4→  grid-template-columns: var(--sidebar-width, 240px) 1fr 280px;
  5→  grid-template-areas:
  6→    "toolbar toolbar toolbar"
  7→    "sidebar canvas rightpanel";
  8→  height: 100%;
  9→  width: 100%;
 10→}
 11→
 12→.toolbar {
 13→  grid-area: toolbar;
 14→  position: relative;
 15→  z-index: 10;
 16→}
 17→
 18→.sidebar {
 19→  grid-area: sidebar;
 20→  min-height: 0;
 21→  overflow-y: auto;
 22→}
 23→
 24→.canvas {
 25→  grid-area: canvas;
 26→  min-width: 0;
 27→  min-height: 0;
 28→  overflow: hidden;
