 60→}
 61→
 62→.previewFallback {
 63→  display: flex;
 64→  align-items: center;
 65→  justify-content: center;
 66→  width: 100%;
 67→  height: 100%;
 68→  min-height: 0;
 69→  font-size: 13px;
 70→  color: var(--color-text-secondary);
 71→  background: radial-gradient(circle at top, rgba(255, 255, 255, 0.6), rgba(243, 243, 240, 0.9)),
 72→    linear-gradient(180deg, #F3F3F0, #EAEAE7);
 73→  border-left: 1px solid var(--color-border);
 74→  position: relative;
 75→  overflow: hidden;
 76→}
 77→
 78→.previewFallback::after {
 79→  content: '';
 80→  position: absolute;
 81→  inset: 0;
 82→  background: linear-gradient(90deg, transparent, rgba(255, 255, 255, 0.4), transparent);
 83→  animation: shimmer 1.5s infinite;
 84→}
 85→
 86→@keyframes shimmer {
 87→  from { transform: translateX(-100%); }
 88→  to { transform: translateX(100%); }
