 178→function retargetManagedViewports(sheets, objectId, oldAssemblyIds = []) {
 179→  const oldAssemblyIdSet = new Set(oldAssemblyIds);
 180→
 181→  return (sheets || []).map((sheet) => ({
 182→    ...sheet,
 183→    viewports: (sheet.viewports || []).map((viewport) => {
 184→      if (viewport.sourceRefId !== objectId && !oldAssemblyIdSet.has(viewport.sourceRefId)) {
 185→        return viewport;
 186→      }
 187→
 188→      if (viewport.sourceView === 'sketch_assembly_top') {
 189→        return { ...viewport, sourceView: 'sketch_object_top', sourceRefId: objectId };
 190→      }
 191→      if (viewport.sourceView === 'sketch_assembly_front') {
 192→        return { ...viewport, sourceView: 'sketch_object_front', sourceRefId: objectId };
 193→      }
 194→      if (viewport.sourceView === 'sketch_assembly_side') {
 195→        return { ...viewport, sourceView: 'sketch_object_side', sourceRefId: objectId };
 196→      }
 197→      if (viewport.sourceView === 'sketch_part_list') {
 198→        return { ...viewport, sourceRefId: objectId, sourceObjectId: objectId };
 199→      }
 200→
 201→      return viewport;
 202→    }),
 203→  }));
 204→}
