 503→        )),
 504→      });
 505→    }
 506→
 507→    case 'ASSEMBLY_DELETE': {
 508→      const managedObject = getManagedObjectForAssembly(state.project, action.assemblyId);
 509→      if (managedObject) return state;
 510→
 511→      const assemblyId = action.assemblyId;
 512→      return applyUpdate(state, {
